// Localiza o primeiro binário .xlsx/.xls/.csv recebido pelo Webhook.
// O n8n nomeia arquivos multipart como data0, data1, ... (com binaryPropertyName=data).
// Renomeia para 'data0' para alimentar o nó Update File com nome estável.
const item = $input.first();
const bin = item.binary || {};
const keys = Object.keys(bin);

if (keys.length === 0) {
  throw new Error('Nenhum arquivo recebido. Envie um .xlsx no campo do form-data.');
}

// Pega o primeiro binário (data0 normalmente).
const sourceKey = keys[0];
const fileBin = bin[sourceKey];
const fileName = (fileBin.fileName || '').toLowerCase();
const mime = (fileBin.mimeType || '').toLowerCase();

const valid = fileName.endsWith('.xlsx') || fileName.endsWith('.xls') || fileName.endsWith('.csv')
  || mime.includes('spreadsheetml') || mime.includes('excel') || mime.includes('csv');

if (!valid) {
  throw new Error(`Arquivo inválido: ${fileBin.fileName || sourceKey}. Envie .xlsx, .xls ou .csv.`);
}

return [{
  json: {
    received_file: fileBin.fileName,
    mime: fileBin.mimeType,
    size_bytes: fileBin.fileSize || null
  },
  binary: { data0: fileBin }
}];
